var e=[{id:`L2_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`기다려.`,JPN:`待て。`,ENG:`Wait.`,TWN:`等等。`},stage:{bg:`DORMITORY_3`,bgm:`THEMA_DIVE_BOTTOM`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`내가 받는다.`,JPN:`俺が出る。`,ENG:`I'll answer it.`,TWN:`我來接。`},stage:{bg:`DORMITORY_3`,bgm:`THEMA_DIVE_BOTTOM`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`......응.`,JPN:`……うん。`,ENG:`Okay.`,TWN:`……嗯。`},stage:{bg:`DORMITORY_3`,bgm:`THEMA_DIVE_BOTTOM`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:null,text:{KOREA:`여보세요.`,JPN:`やあ。`,ENG:`Hello?`,TWN:`喂。`},stage:{bg:`DORMITORY_3`,bgm:`THEMA_DIVE_BOTTOM`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`DORMITORY_3`,bgm:`THEMA_DIVE_BOTTOM`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SEONGTAE_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:null,text:{KOREA:`흠, 대답이 없군. 그럼 역시 도현 그 얼간이 녀석은 당했다고 봐도 되겠지?`,JPN:`ふむ、返事がないってことは、やっぱりリョウ……あのマヌケはやられたと思っていいのか？`,ENG:`Hmm, no answer. Then I guess that dimwit—Dohyun—is not with us anymore?`,TWN:`哼，怎麼不回應，難道說道賢那個笨蛋被殺了？`},stage:{bg:`DORMITORY_3`,bgm:`THEMA_DIVE_BOTTOM`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SEONGTAE_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:null,text:{KOREA:`누군진 몰라도 꽤나 성급한 장난을 쳤어.`,JPN:`誰だか知らないが、イタズラにしてはやりすぎたな。`,ENG:`Whoever you are, you got reckless.`,TWN:`你這是在自尋死路啊。`},stage:{bg:`DORMITORY_3`,bgm:`THEMA_DIVE_BOTTOM`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SEONGTAE_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`넌 누구지?`,JPN:`お前は誰だ？`,ENG:`Who are you?`,TWN:`你是誰？`},stage:{bg:`DORMITORY_3`,bgm:`THEMA_DIVE_BOTTOM`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SEONGTAE_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:null,text:{KOREA:`궁금한가? 조금만 기다리라고, 곧 찾아갈 테니까.`,JPN:`気になるのか？　少しだけ待ってろ。もうすぐ行くから。`,ENG:`You want to know? Just hang tight. I'll be there soon.`,TWN:`你想知道嗎？我馬上就去找你，等著吧。`},stage:{bg:`DORMITORY_3`,bgm:`THEMA_DIVE_BOTTOM`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SEONGTAE_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:null,text:{KOREA:`아 참, 유서는 미리 써놓고.`,JPN:`そうだ、遺書は先に書いておいたほうがいいぞ。`,ENG:`Oh, you might want to write your will in the meantime.`,TWN:`對了，先寫好遺書。`},stage:{bg:`DORMITORY_3`,bgm:`THEMA_DIVE_BOTTOM`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SEONGTAE_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`누구야? 뭐라고 한 건데?`,JPN:`誰？　なにか話した？`,ENG:`Who was that? What did they say?`,TWN:`是誰？他說了什麼？`},stage:{bg:`DORMITORY_3`,bgm:`THEMA_DIVE_BOTTOM`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`이 전화기, 아무래도 위치 추적이 되고 있었나 보군.`,JPN:`この携帯、どうやら位置を追跡されていたようだ。`,ENG:`It seems like they've got a tracker on this phone.`,TWN:`這電話可能有定位功能。`},stage:{bg:`DORMITORY_3`,bgm:`THEMA_DIVE_BOTTOM`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SEONGTAE_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`놈들이 몰려올 거야, 당장 여길 뜬다!`,JPN:`奴らが来ている。今すぐここを離れる！`,ENG:`They'll be barging in here any minute. We've got to leave right now!`,TWN:`敵人要來了，馬上離開這裡！`},stage:{bg:`DORMITORY_3`,bgm:`THEMA_DIVE_BOTTOM`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SEONGTAE_MILITIA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`JIHUN_MILITIA_NULL_NULL`,text:{KOREA:`......우리 여기에 노크 하고 지내는 이웃 있었나?`,JPN:`……この辺の隣人さんでノックする人なんていたか？`,ENG:`... Since when did our neighbors knock around here?`,TWN:`……我們的鄰居進門前會敲門嗎？`},stage:{bg:`DORMITORY_3`,bgm:`BATTLE_DESIGNPLAZA_NIGHT`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`JIHUN_MILITIA_NULL_NULL`,face:`UNIT_HATE`}}}},{id:`L28_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`없었지! 둘 다 무기 챙겨!`,JPN:`そんな人はいない！　二人とも、武器を！`,ENG:`Never! Grab your weapons!`,TWN:`不會！拿起武器！`},stage:{bg:`DORMITORY_3`,bgm:`BATTLE_DESIGNPLAZA_NIGHT`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SEONGTAE_MILITIA_NULL_NULL`,face:`UNIT_HATE`},R:null}}}];export{e as default};